### 2. WebCrypto API Tests

```javascript
describe("WebCrypto Compatibility", () => {
    test("AES-GCM encryption available", async () => {
        const result = await page.evaluate(async () => {
            try {
                const key = await crypto.subtle.generateKey(
                    { name: "AES-GCM", length: 256 },
                    true,
                    ["encrypt", "decrypt"]
                );
                return { success: true, keyType: key.type };
            } catch (e) {
                return { success: false, error: e.message };
            }
        });
        expect(result.success).toBe(true);
    });

    test("PBKDF2 derivation works", async () => {
        const result = await page.evaluate(async () => {
            const enc = new TextEncoder();
            const keyMaterial = await crypto.subtle.importKey(
                "raw",
                enc.encode("password"),
                "PBKDF2",
                false,
                ["deriveBits"]
            );
            const bits = await crypto.subtle.deriveBits(
                {
                    name: "PBKDF2",
                    salt: enc.encode("salt"),
                    iterations: 100000,
                    hash: "SHA-256"
                },
                keyMaterial,
                256
            );
            return { success: true, length: bits.byteLength };
        });
        expect(result.success).toBe(true);
        expect(result.length).toBe(32);
    });

    test("SubtleCrypto timing attack mitigations", async () => {
        // Verify constant-time comparison is used
        const timings = await page.evaluate(async () => {
            const times = [];
            for (let i = 0; i < 100; i++) {
                const start = performance.now();
                await attemptDecrypt(wrongKey);
                times.push(performance.now() - start);
            }
            return { mean: mean(times), stddev: stddev(times) };
        });
        // High variance would indicate timing leaks
        expect(timings.stddev / timings.mean).toBeLessThan(0.5);
    });
});
