### 5. Web Worker Tests

```javascript
describe("Web Worker Compatibility", () => {
    test("Crypto worker loads", async () => {
        const result = await page.evaluate(async () => {
            return new Promise((resolve) => {
                const worker = new Worker("/crypto-worker.js");
                worker.onmessage = (e) => {
                    if (e.data.type === "ready") {
                        resolve({ success: true });
                        worker.terminate();
                    }
                };
                worker.onerror = (e) => {
                    resolve({ success: false, error: e.message });
                    worker.terminate();
                };
            });
        });
        expect(result.success).toBe(true);
    });

    test("Decryption happens off main thread", async () => {
        const mainThreadBlocked = await page.evaluate(async () => {
            const start = performance.now();
            let blocked = false;

            const checkInterval = setInterval(() => {
                const now = performance.now();
                if (now - start > 100) {
                    blocked = true;
                }
            }, 10);

            await decryptLargeArchive();
            clearInterval(checkInterval);

            return blocked;
        });

        // Main thread should not be blocked during decryption
        expect(mainThreadBlocked).toBe(false);
    });
});
```

